// // This module selects the first input when sel is 1 and the second input when sel is 0
module mux_2to1_8bit(
    input           sel,
    input   [7:0]   data_in0,
    input   [7:0]   data_in1,

    output  [7:0]   data_out
);

// Multiplexer implementation
assign data_out = (sel) ? data_in1 : data_in0;

endmodule
